Given this three-sum algorithm:

```
ARRAY = [-1, 0, 1, 2, -1, -4]
SORT(ARRAY)  // [-4, -1, -1, 0, 1, 2]
RESULT = []

for i = 0 to length(ARRAY) - 3:
    if i > 0 and ARRAY[i] = ARRAY[i-1]:
        continue

    left = i + 1
    right = length(ARRAY) - 1

    while left < right:
        sum = ARRAY[i] + ARRAY[left] + ARRAY[right]
        if sum = 0:
            RESULT.add([ARRAY[i], ARRAY[left], ARRAY[right]])
            while left < right and ARRAY[left] = ARRAY[left + 1]:
                left = left + 1
            while left < right and ARRAY[right] = ARRAY[right - 1]:
                right = right - 1
            left = left + 1
            right = right - 1
        elif sum < 0:
            left = left + 1
        else:
            right = right - 1
```

